flow.set('deviceState', {
    ev: { on: false, lastChange: 0, amps: 0 },
    boiler: { on: false, lastChange: 0 },
    pool: { on: false, lastChange: 0 },
    heaterRight: { on: false, lastChange: 0 },
    heaterTable: { on: false, lastChange: 0 },
    acLiving: { on: false, lastChange: 0 },
    acMancave: { on: false, lastChange: 0 },
    acBureau: { on: false, lastChange: 0 },
    acSlaapkamer: { on: false, lastChange: 0 }
});
flow.set('actionLog', []);
return null;

const config = flow.get('config') || {};
let deviceState = flow.get('deviceState') || {};
let actionLog = flow.get('actionLog') || [];
const now = Date.now();
const units = config.units || {};

// === HELPERS ===
function fmtW(w) { return Math.abs(w) >= 1000 ? (w/1000).toFixed(1) + 'kW' : Math.round(w) + 'W'; }
function fmtTime(h) { return String(Math.floor(h)).padStart(2,'0') + ':' + String(Math.round((h % 1) * 60)).padStart(2,'0'); }

function getTariffInfo(d) {
    const time = d.getHours() + d.getMinutes() / 60;
    const isWeekend = d.getDay() === 0 || d.getDay() === 6;
    if (isWeekend) {
        if (time >= 1 && time < 7) return { tariff: 'superdal', max: 8000, end: 7, next: 'dal', nextTime: '07:00' };
        if (time >= 7 && time < 11) return { tariff: 'dal', max: 5000, end: 11, next: 'superdal', nextTime: '11:00' };
        if (time >= 11 && time < 17) return { tariff: 'superdal', max: 8000, end: 17, next: 'dal', nextTime: '17:00' };
        return { tariff: 'dal', max: 5000, end: 1, next: 'superdal', nextTime: '01:00' };
    } else {
        if (time >= 1 && time < 7) return { tariff: 'superdal', max: 8000, end: 7, next: 'piek', nextTime: '07:00' };
        if (time >= 7 && time < 11) return { tariff: 'piek', max: 2500, end: 11, next: 'dal', nextTime: '11:00' };
        if (time >= 11 && time < 17) return { tariff: 'dal', max: 5000, end: 17, next: 'piek', nextTime: '17:00' };
        if (time >= 17 && time < 22) return { tariff: 'piek', max: 2500, end: 22, next: 'dal', nextTime: '22:00' };
        return { tariff: 'dal', max: 5000, end: 1, next: 'superdal', nextTime: '01:00' };
    }
}

// Get NEXT non-piek period for planning
function getNextNonPiek(d) {
    const time = d.getHours() + d.getMinutes() / 60;
    const isWeekend = d.getDay() === 0 || d.getDay() === 6;
    if (isWeekend) return { time: '01:00', tariff: 'superdal', max: 8000 };
    if (time >= 7 && time < 11) return { time: '11:00', tariff: 'dal', max: 5000 };
    if (time >= 17 && time < 22) return { time: '22:00', tariff: 'dal', max: 5000 };
    if (time >= 22 || time < 1) return { time: '01:00', tariff: 'superdal', max: 8000 };
    return { time: '01:00', tariff: 'superdal', max: 8000 };
}

function canSwitch(device, targetState) {
    const state = deviceState[device];
    if (!state) return true;
    const elapsed = (now - state.lastChange) / 1000;
    const minTime = targetState ? (config.minOffTime || 180) : (config.minOnTime || 300);
    return elapsed >= minTime;
}

function updateState(device, on, extra = {}) {
    if (!deviceState[device]) deviceState[device] = { on: false, lastChange: 0 };
    if (deviceState[device].on !== on) deviceState[device].lastChange = now;
    deviceState[device].on = on;
    Object.assign(deviceState[device], extra);
    flow.set('deviceState', deviceState);
}

function logAction(action) {
    const ts = new Date().toLocaleTimeString('nl-NL', {hour: '2-digit', minute: '2-digit'});
    actionLog.unshift(`${ts} ${action}`);
    if (actionLog.length > 15) actionLog.pop();
    flow.set('actionLog', actionLog);
}

function parseOverride(val) {
    if (!val) return 'auto';
    if (val.includes('Auto')) return 'auto';
    if (val.includes('Koelen')) return 'cool';
    if (val.includes('Verwarmen') || val.includes('Aan') || val.includes('Laden')) return 'heat';
    if (val.includes('Uit')) return 'off';
    return 'auto';
}

// === DATA ===
const p1 = (msg.p1_power || 0) * (units.p1 || 1);
const pv = (msg.pv_power || 0) * (units.pv || 1);
const d = new Date();
const tariffInfo = getTariffInfo(d);
const tariff = tariffInfo.tariff;
const maxImport = tariffInfo.max;
const hyst = config.hysteresis || 300;
const nextNonPiek = getNextNonPiek(d);

const isSummer = msg.pool_season === 'on';
const isExporting = p1 < 0;

const ovr = {
    acLiving: parseOverride(msg.ovr_ac_living),
    acSlaapkamer: parseOverride(msg.ovr_ac_slaapkamer),
    acBureau: parseOverride(msg.ovr_ac_bureau),
    acMancave: parseOverride(msg.ovr_ac_mancave),
    pool: parseOverride(msg.ovr_pool),
    boiler: parseOverride(msg.ovr_boiler),
    ev: parseOverride(msg.ovr_ev)
};

const evState = msg.ev_state || 128;
const evPlugged = evState !== 128;
const evCharging = evState === 132;
const evReady = evState === 129;
const evDone = evState === 130;
let evStatusText = evState === 128 ? 'Geen auto' : evState === 129 ? 'Klaar' : evState === 130 ? 'Vol' : evState === 132 ? 'Laden' : `Code ${evState}`;

const boilerOn = msg.boiler_switch === 'on';
const boilerForce = msg.boiler_force === 'on';
const boilerW = (msg.boiler_power || 0) * (units.boiler || 1);
const boilerFull = boilerW < (config.boilerIdleThreshold || 50);
const poolW = (msg.pool_power || 0) * (units.poolHeat || 1);
const poolHeating = poolW > (config.poolIdlePower || 100);
const hrOn = msg.heater_right_switch === 'on';
const htOn = msg.heater_table_switch === 'on';
const evOn = msg.ev_switch === 'on';
const evW = (msg.ev_power || 0) * (units.ev || 1);
const evLimit = msg.ev_limit || 6;
const acLivingOn = msg.ac_living_state !== 'off';
const acMancaveOn = msg.ac_mancave_state !== 'off';
const acBureauOn = msg.ac_bureau_state !== 'off';
const acSlaapkamerOn = msg.ac_slaapkamer_state !== 'off';
const tempLiving = msg.temp_living || 20;
const tempBedroom = msg.temp_bedroom || 20;
const tempMancave = msg.temp_mancave || 20;
const coolThreshold = config.summerCoolThreshold || 25;

// Beschikbaar vermogen = wat we nog kunnen toevoegen voordat we limiet raken
let avail = -p1 + maxImport;
// Voor planning: hoeveel extra kunnen we aanzetten
let headroom = avail;

const plan = [];
const gridIcon = isExporting ? '🟢' : (p1 > maxImport * 0.8 ? '🔴' : '🟡');
plan.push(`${gridIcon} ${tariff.toUpperCase()} | ${fmtW(p1)} net | ☀️${fmtW(pv)} | ${fmtW(avail)} vrij`);
plan.push(`${isSummer ? '☀️ Zomer' : '❄️ Winter'} | 🔌 ${evStatusText}`);

let decisions = {
    ev: { action: 'none', amps: evLimit },
    boiler: { action: 'none' },
    pool: { action: 'none' },
    heaterRight: { action: 'none' },
    heaterTable: { action: 'none' },
    acLiving: { action: 'none', mode: 'off', temp: 22 },
    acMancave: { action: 'none', mode: 'off', temp: 17 },
    acBureau: { action: 'none', mode: 'off', temp: 22 },
    acSlaapkamer: { action: 'none', mode: 'off', temp: 22 }
};

// === MANUAL OVERRIDES FIRST ===
if (ovr.pool === 'heat' && !poolHeating) {
    decisions.pool.action = 'heat';
    plan.push(`🏊 Pool: MANUEEL AAN`);
} else if (ovr.pool === 'off' && poolHeating) {
    decisions.pool.action = 'off';
    plan.push(`🏊 Pool: MANUEEL UIT`);
}

if (ovr.boiler === 'heat' && !boilerOn) {
    decisions.boiler.action = 'on';
    plan.push(`🔥 Boiler: MANUEEL AAN`);
} else if (ovr.boiler === 'off' && boilerOn) {
    decisions.boiler.action = 'off';
    plan.push(`🔥 Boiler: MANUEEL UIT`);
}

if (ovr.ev === 'heat' && evPlugged && !evCharging && !evDone) {
    decisions.ev = { action: 'on', amps: config.evMaxAmps || 16 };
    plan.push(`🔌 EV: MANUEEL LADEN`);
} else if (ovr.ev === 'off' && evCharging) {
    decisions.ev = { action: 'off', amps: 0 };
    plan.push(`🔌 EV: MANUEEL UIT`);
}

const acUnits = ['acLiving', 'acSlaapkamer', 'acBureau', 'acMancave'];
const acNames = { acLiving: 'Living', acSlaapkamer: 'Slaapkamer', acBureau: 'Bureau', acMancave: 'Mancave' };
const acStates = { acLiving: acLivingOn, acSlaapkamer: acSlaapkamerOn, acBureau: acBureauOn, acMancave: acMancaveOn };
const acTemps = { acLiving: 22, acSlaapkamer: 22, acBureau: 22, acMancave: 17 };

for (const ac of acUnits) {
    const o = ovr[ac];
    const isOn = acStates[ac];
    const temp = acTemps[ac];
    if (o === 'cool') {
        decisions[ac] = { action: 'cool', mode: 'cool', temp: temp };
        if (!isOn) plan.push(`❄️ ${acNames[ac]}: MANUEEL KOELEN`);
    } else if (o === 'heat') {
        decisions[ac] = { action: 'heat', mode: 'heat', temp: temp };
        if (!isOn) plan.push(`🔥 ${acNames[ac]}: MANUEEL VERWARMEN`);
    } else if (o === 'off' && isOn) {
        decisions[ac] = { action: 'off', mode: 'off', temp: temp };
        plan.push(`⏹️ ${acNames[ac]}: MANUEEL UIT`);
    }
}

if (boilerForce && !boilerFull && ovr.boiler === 'auto') {
    decisions.boiler.action = 'on';
    plan.push(`🔥 Boiler: FORCE`);
}

// === WINTER LOGIC ===
if (!isSummer) {
    // EV
    if (ovr.ev === 'auto' && decisions.ev.action === 'none') {
        if (!evPlugged) {
            // Geen plan entry nodig - al in header
        } else if (evDone) {
            plan.push(`🔌 EV: Vol ✓`);
        } else {
            const wpa = config.evWattsPerAmp || 692;
            const minA = config.evMinAmps || 6;
            const maxA = config.evMaxAmps || 16;
            const minEvW = minA * wpa;
            let targetA = Math.floor(headroom / wpa);
            targetA = Math.max(minA, Math.min(maxA, targetA));

            if (evCharging) {
                if (headroom < minEvW - hyst && canSwitch('ev', false)) {
                    decisions.ev = { action: 'off', amps: 0 };
                    plan.push(`🔌 EV: Pauzeren (${fmtW(headroom)} < ${fmtW(minEvW)})`);
                } else {
                    plan.push(`🔌 EV: Laden @ ${evLimit}A`);
                }
            } else if (evReady) {
                if (tariff === 'piek') {
                    plan.push(`🔌 EV: Wacht op dal (${tariffInfo.nextTime})`);
                } else if (headroom >= minEvW && canSwitch('ev', true)) {
                    decisions.ev = { action: 'on', amps: targetA };
                    plan.push(`🔌 EV: Starten @ ${targetA}A`);
                    headroom -= targetA * wpa;
                } else {
                    plan.push(`🔌 EV: Wacht op ${fmtW(minEvW)} (nu ${fmtW(headroom)})`);
                }
            }
        }
    }

    // Boiler
    if (ovr.boiler === 'auto' && decisions.boiler.action === 'none') {
        const bw = config.boilerPower || 2500;
        const time = d.getHours() + d.getMinutes() / 60;
        const deadline = config.boilerDeadlineWinter || 6.5;
        const urgent = time < deadline && tariff === 'superdal' && !boilerFull;

        if (boilerFull) {
            plan.push(`🔥 Boiler: Vol ✓`);
        } else if (boilerOn) {
            plan.push(`🔥 Boiler: Verwarmt`);
        } else if (urgent) {
            decisions.boiler.action = 'on';
            plan.push(`🔥 Boiler: URGENT (deadline ${fmtTime(deadline)})`);
            headroom -= bw;
        } else if (tariff !== 'superdal') {
            plan.push(`🔥 Boiler: Wacht op superdal (${nextNonPiek.tariff === 'superdal' ? nextNonPiek.time : '01:00'})`);
        } else if (headroom >= bw - hyst && canSwitch('boiler', true)) {
            decisions.boiler.action = 'on';
            plan.push(`🔥 Boiler: Starten`);
            headroom -= bw;
        } else {
            plan.push(`🔥 Boiler: Wacht op ${fmtW(bw)} (nu ${fmtW(headroom)})`);
        }
    }

    // AC Living
    if (ovr.acLiving === 'auto' && decisions.acLiving.action === 'none') {
        if (acLivingOn) {
            if (tariff === 'piek' && headroom < -hyst && canSwitch('acLiving', false)) {
                decisions.acLiving = { action: 'off', mode: 'off', temp: 21 };
                plan.push(`🔥 AC Living: Load shed (piek)`);
            } else {
                plan.push(`🔥 AC Living: Verwarmt (${tempLiving.toFixed(1)}°C)`);
            }
        } else {
            const pw = config.acLivingPower || 1500;
            if (tariff === 'piek') {
                plan.push(`🔥 AC Living: Wacht tot na piek (${tariffInfo.nextTime})`);
            } else if (headroom >= pw - hyst && canSwitch('acLiving', true)) {
                decisions.acLiving = { action: 'heat', mode: 'heat', temp: 21 };
                plan.push(`🔥 AC Living: Aanzetten`);
                headroom -= pw;
            } else {
                plan.push(`🔥 AC Living: Wacht op ${fmtW(pw)} (nu ${fmtW(headroom)})`);
            }
        }
    }

    // AC Mancave
    if (ovr.acMancave === 'auto' && decisions.acMancave.action === 'none') {
        if (acMancaveOn) {
            plan.push(`🔥 AC Mancave: Verwarmt (${tempMancave.toFixed(1)}°C)`);
        } else {
            const pw = config.acMancavePower || 1000;
            if (tariff === 'piek') {
                plan.push(`🔥 AC Mancave: Wacht tot na piek (${tariffInfo.nextTime})`);
            } else if (headroom >= pw - hyst && canSwitch('acMancave', true)) {
                decisions.acMancave = { action: 'heat', mode: 'heat', temp: 17 };
                plan.push(`🔥 AC Mancave: Aanzetten`);
                headroom -= pw;
            }
        }
    }

    // HEATER TABLE - altijd plan entry!
    const htW = config.heaterTablePower || 4100;
    if (htOn) {
        if (headroom < -hyst && canSwitch('heaterTable', false)) {
            decisions.heaterTable.action = 'off';
            plan.push(`🔥 Heater T: Uitzetten (overbelast)`);
        } else {
            plan.push(`🔥 Heater T: Aan (${fmtW(htW)})`);
        }
    } else {
        // Niet aan - waarom niet en wanneer wel?
        if (tariff === 'piek') {
            // Bereken wanneer dal of superdal begint
            plan.push(`🔥 Heater T: Wacht op dal (${tariffInfo.nextTime})`);
        } else if (headroom < htW - hyst) {
            plan.push(`🔥 Heater T: Wacht op ${fmtW(htW)} (nu ${fmtW(headroom)})`);
        } else if (!canSwitch('heaterTable', true)) {
            plan.push(`🔥 Heater T: Wacht (min tijd)`);
        } else {
            // Alle condities voldaan
            decisions.heaterTable.action = 'on';
            plan.push(`🔥 Heater T: Aanzetten`);
            headroom -= htW;
        }
    }

    // HEATER RIGHT - altijd plan entry!
    const hrW = config.heaterRightPower || 2500;
    if (hrOn) {
        if (headroom < -hyst && canSwitch('heaterRight', false)) {
            decisions.heaterRight.action = 'off';
            plan.push(`🔥 Heater R: Uitzetten (overbelast)`);
        } else {
            plan.push(`🔥 Heater R: Aan (${fmtW(hrW)})`);
        }
    } else {
        if (tariff === 'piek') {
            plan.push(`🔥 Heater R: Wacht op dal (${tariffInfo.nextTime})`);
        } else if (headroom < hrW - hyst) {
            plan.push(`🔥 Heater R: Wacht op ${fmtW(hrW)} (nu ${fmtW(headroom)})`);
        } else if (!canSwitch('heaterRight', true)) {
            plan.push(`🔥 Heater R: Wacht (min tijd)`);
        } else {
            decisions.heaterRight.action = 'on';
            plan.push(`🔥 Heater R: Aanzetten`);
            headroom -= hrW;
        }
    }

// === SUMMER LOGIC ===
} else {
    // Pool
    if (ovr.pool === 'auto' && decisions.pool.action === 'none') {
        const pw = config.poolActivePower || 2000;
        if (poolHeating) {
            if (headroom < -hyst && canSwitch('pool', false)) {
                decisions.pool.action = 'off';
                plan.push(`🏊 Pool: Pauzeren`);
            } else {
                plan.push(`🏊 Pool: Verwarmt`);
            }
        } else if (headroom >= pw - hyst && canSwitch('pool', true)) {
            decisions.pool.action = 'heat';
            plan.push(`🏊 Pool: Starten (low fan)`);
            headroom -= pw;
        } else {
            plan.push(`🏊 Pool: Wacht op ${fmtW(pw)} (nu ${fmtW(headroom)})`);
        }
    }

    // Boiler
    if (ovr.boiler === 'auto' && decisions.boiler.action === 'none') {
        const bw = config.boilerPower || 2500;
        if (boilerFull) {
            plan.push(`🔥 Boiler: Vol ✓`);
        } else if (boilerOn) {
            plan.push(`🔥 Boiler: Verwarmt`);
        } else if (headroom >= bw - hyst && canSwitch('boiler', true)) {
            decisions.boiler.action = 'on';
            plan.push(`🔥 Boiler: Starten`);
            headroom -= bw;
        } else {
            plan.push(`🔥 Boiler: Wacht op ${fmtW(bw)}`);
        }
    }

    // EV
    if (ovr.ev === 'auto' && decisions.ev.action === 'none') {
        if (!evPlugged) {
            // Skip
        } else if (evDone) {
            plan.push(`🔌 EV: Vol ✓`);
        } else {
            const wpa = config.evWattsPerAmp || 692;
            const minA = config.evMinAmps || 6;
            const minEvW = minA * wpa;
            let targetA = Math.floor(headroom / wpa);
            targetA = Math.max(minA, Math.min(config.evMaxAmps || 16, targetA));

            if (evCharging) {
                plan.push(`🔌 EV: Laden @ ${evLimit}A`);
            } else if (evReady && headroom >= minEvW && tariff !== 'piek' && canSwitch('ev', true)) {
                decisions.ev = { action: 'on', amps: targetA };
                plan.push(`🔌 EV: Starten @ ${targetA}A`);
                headroom -= targetA * wpa;
            } else if (tariff === 'piek') {
                plan.push(`🔌 EV: Wacht op dal`);
            } else {
                plan.push(`🔌 EV: Wacht op ${fmtW(minEvW)}`);
            }
        }
    }

    // Cooling (alleen bij export)
    if (isExporting) {
        const coolOrder = ['acLiving', 'acSlaapkamer', 'acBureau', 'acMancave'];
        const temps = { acLiving: tempLiving, acSlaapkamer: tempBedroom, acBureau: tempLiving, acMancave: tempMancave };
        const powers = { acLiving: 1500, acSlaapkamer: 1000, acBureau: 1000, acMancave: 1000 };

        for (const ac of coolOrder) {
            if (ovr[ac] !== 'auto') continue;
            if (decisions[ac].action !== 'none') continue;
            const pw = config[ac + 'Power'] || powers[ac];
            const temp = temps[ac];
            const isOn = acStates[ac];

            if (temp > coolThreshold && headroom >= pw) {
                if (!isOn && canSwitch(ac, true)) {
                    decisions[ac] = { action: 'cool', mode: 'cool', temp: 22 };
                    plan.push(`❄️ ${acNames[ac]}: Koelen (${temp.toFixed(1)}°C)`);
                    headroom -= pw;
                } else if (isOn) {
                    plan.push(`❄️ ${acNames[ac]}: Koelt (${temp.toFixed(1)}°C)`);
                }
            } else if (isOn && headroom < -hyst && canSwitch(ac, false)) {
                decisions[ac] = { action: 'off', mode: 'off', temp: 22 };
            }
        }
    } else {
        // Niet exporting - koeling uit
        for (const ac of acUnits) {
            if (ovr[ac] !== 'auto') continue;
            if (acStates[ac] && canSwitch(ac, false)) {
                decisions[ac] = { action: 'off', mode: 'off', temp: 22 };
            }
        }
        plan.push(`❄️ Koeling: Wacht op export`);
    }
}

plan.push(`✅ ${fmtW(headroom)} beschikbaar`);

// === OUTPUTS ===
const outputs = new Array(12).fill(null);
const executed = [];

if (decisions.ev.action === 'on') {
    outputs[0] = { payload: { action: 'turn_on', amps: decisions.ev.amps } };
    updateState('ev', true, { amps: decisions.ev.amps });
    logAction(`🔌 EV AAN @ ${decisions.ev.amps}A`);
    executed.push(`EV aan`);
} else if (decisions.ev.action === 'off') {
    outputs[0] = { payload: { action: 'turn_off' } };
    updateState('ev', false);
    logAction(`🔌 EV UIT`);
    executed.push(`EV uit`);
} else if (decisions.ev.action === 'adjust') {
    outputs[0] = { payload: { action: 'adjust', amps: decisions.ev.amps } };
    updateState('ev', true, { amps: decisions.ev.amps });
    logAction(`🔌 EV ${decisions.ev.amps}A`);
}

if (decisions.boiler.action === 'on' && !boilerOn) {
    outputs[1] = { payload: 'turn_on' };
    updateState('boiler', true);
    logAction(`🔥 Boiler AAN`);
    executed.push(`Boiler aan`);
} else if (decisions.boiler.action === 'off' && boilerOn) {
    outputs[1] = { payload: 'turn_off' };
    updateState('boiler', false);
    logAction(`🔥 Boiler UIT`);
    executed.push(`Boiler uit`);
}

if (decisions.pool.action === 'heat' && !poolHeating) {
    outputs[2] = { payload: { mode: 'heat', fan: 'low' } };
    updateState('pool', true);
    logAction(`🏊 Pool AAN`);
    executed.push(`Pool aan`);
} else if (decisions.pool.action === 'off' && poolHeating) {
    outputs[2] = { payload: { mode: 'off', fan: 'low' } };
    updateState('pool', false);
    logAction(`🏊 Pool UIT`);
    executed.push(`Pool uit`);
}

if (decisions.heaterRight.action === 'on' && !hrOn) {
    outputs[3] = { payload: 'turn_on' };
    updateState('heaterRight', true);
    logAction(`🔥 HR AAN`);
    executed.push(`Heater R aan`);
} else if (decisions.heaterRight.action === 'off' && hrOn) {
    outputs[3] = { payload: 'turn_off' };
    updateState('heaterRight', false);
    logAction(`🔥 HR UIT`);
    executed.push(`Heater R uit`);
}

if (decisions.heaterTable.action === 'on' && !htOn) {
    outputs[4] = { payload: 'turn_on' };
    updateState('heaterTable', true);
    logAction(`🔥 HT AAN`);
    executed.push(`Heater T aan`);
} else if (decisions.heaterTable.action === 'off' && htOn) {
    outputs[4] = { payload: 'turn_off' };
    updateState('heaterTable', false);
    logAction(`🔥 HT UIT`);
    executed.push(`Heater T uit`);
}

if (decisions.acLiving.action !== 'none') {
    outputs[5] = { payload: decisions.acLiving };
    updateState('acLiving', decisions.acLiving.mode !== 'off');
    logAction(`AC Liv ${decisions.acLiving.mode}`);
}
if (decisions.acMancave.action !== 'none') {
    outputs[6] = { payload: decisions.acMancave };
    updateState('acMancave', decisions.acMancave.mode !== 'off');
    logAction(`AC Man ${decisions.acMancave.mode}`);
}
if (decisions.acBureau.action !== 'none') {
    outputs[7] = { payload: decisions.acBureau };
    updateState('acBureau', decisions.acBureau.mode !== 'off');
    logAction(`AC Bur ${decisions.acBureau.mode}`);
}
if (decisions.acSlaapkamer.action !== 'none') {
    outputs[8] = { payload: decisions.acSlaapkamer };
    updateState('acSlaapkamer', decisions.acSlaapkamer.mode !== 'off');
    logAction(`AC Slp ${decisions.acSlaapkamer.mode}`);
}

outputs[9] = { payload: { plan, actionLog, tariff, p1, pv, avail, headroom, ovr, isSummer, isExporting } };

const statusLine = `${tariff.toUpperCase()} | ${fmtW(p1)} | ☀️${fmtW(pv)} | ${fmtW(avail)} vrij`;
const planText = plan.join(' • ');
const actionsText = actionLog.slice(0,5).join(' | ') || '-';
outputs[10] = { payload: { status: statusLine, plan: planText.substring(0, 250), actions: actionsText.substring(0, 250) } };

if (executed.length > 0 && config.enableNotifications) {
    outputs[11] = { payload: { title: '⚡ PM', message: executed.join(', ') } };
}

node.status({ fill: isExporting ? 'green' : (p1 > maxImport * 0.8 ? 'red' : 'yellow'), shape: 'dot', text: statusLine });
return outputs;

if (!msg.payload) return null;
const a = msg.payload.action, amps = msg.payload.amps || 6;
if (a === 'turn_on' || a === 'adjust') {
    return [
        { payload: { domain: 'number', service: 'set_value', data: { entity_id: 'number.abb_terra_ac_current_limit', value: amps } } },
        a === 'turn_on' ? { payload: { domain: 'switch', service: 'turn_on', data: { entity_id: 'switch.abb_terra_ac_charging' } } } : null
    ].filter(x => x);
} else if (a === 'turn_off') {
    return { payload: { domain: 'switch', service: 'turn_off', data: { entity_id: 'switch.abb_terra_ac_charging' } } };
}
return null;

if (!msg.payload) return null;
return {
    payload: {
        domain: 'climate',
        service: 'set_hvac_mode',
        data: {
            entity_id: 'climate.98d8639f920c',
            hvac_mode: msg.payload.mode
        }
    }
};
